class TooltipEl extends HTMLElement {
  static get __BLANK__() {
    return ['data-text', 'disabled'];
  }

  __BLANK__Callback() {
    this.innerHTML = `<span>${this.dataset.text}</span>`;
  }

  attributeChangedCallback(name, old, val) {
    if (name === 'data-text') this.querySelector('span').textContent = val;
  }
}
